node -e "
const fs = require('fs');
const file = '{FILE}';
const content = fs.readFileSync(file, 'utf8');
const issues = [];

// Check for render calls in loops
if (/for\s*\(.*\)\s*\{[^}]*render\(\)/.test(content)) {
  issues.push('⚠ render() called in loop (will cause performance issues)');
}

// Check for synchronous DOM operations
if (/document\.querySelector.*\s*=\s*['\"][^'\"]*['\"];/g.test(content)) {
  issues.push('ℹ Cache DOM queries outside event handlers if possible');
}

// Check for large array operations
if (/MOCK_PLACES.*length\s*>\s*500|places\.length\s*>\s*500/.test(content)) {
  issues.push('⚠ Large dataset detected (>500 places) - consider pagination or virtualization');
}

// Check for updateMapMarkers debouncing
if (/updateMapMarkers/g.test(content) && !/(debounce|throttle)/.test(content)) {
  issues.push('ℹ updateMapMarkers called frequently - consider debouncing');
}

if (issues.length > 0) {
  console.warn(issues.join('\\n'));
} else {
  console.log('✓ Performance check passed');
}
" -- '{FILE}' || true

node -e "
const fs = require('fs');
const file = '{FILE}';
const content = fs.readFileSync(file, 'utf8');
const issues = [];

// Check for inline styles
if (/style=\"/.test(content)) issues.push('⚠ Inline styles detected (use CSS classes)');

// Check for unminified Leaflet CDN
if (!content.includes('integrity=') && content.includes('leaflet')) {
  issues.push('⚠ Leaflet CSS/JS should include integrity attribute');
}

// Check for async/defer on scripts
if (/<script.*src=.*(?!async|defer)/g.test(content)) {
  issues.push('ℹ Consider async/defer on script tags for performance');
}

if (issues.length > 0) {
  console.warn(issues.join('\\n'));
} else {
  console.log('✓ HTML performance check passed');
}
" -- '{FILE}' || true
